{
  "name": "Chương trình Quay số May mắn",
  "description": "Một ứng dụng quay số trúng thưởng với 8 giải từ Giải tám đến Đặc biệt, hỗ trợ quay ngẫu nhiên 00-99 trong 7 giây."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type PrizeId = 
  | 'DAC_BIET'
  | 'GIAI_NHAT'
  | 'GIAI_NHI'
  | 'GIAI_BA'
  | 'GIAI_TU'
  | 'GIAI_NAM'
  | 'GIAI_SAU'
  | 'GIAI_BAY'
  | 'GIAI_TAM';

export interface PrizeInfo {
  id: PrizeId;
  label: string;
}

export interface DrawingState {
  isDrawing: boolean;
  rollingNumber: string;
  targetPrize: PrizeId | null;
  secondsRemaining: number;
}

import { PrizeInfo } from './types';

export const PRIZES: PrizeInfo[] = [
  { id: 'DAC_BIET', label: 'Đặc biệt' },
  { id: 'GIAI_NHAT', label: 'Giải nhất' },
  { id: 'GIAI_NHI', label: 'Giải nhì' },
  { id: 'GIAI_BA', label: 'Giải ba' },
  { id: 'GIAI_TU', label: 'Giải tư' },
  { id: 'GIAI_NAM', label: 'Giải năm' },
  { id: 'GIAI_SAU', label: 'Giải sáu' },
  { id: 'GIAI_BAY', label: 'Giải bảy' },
  { id: 'GIAI_TAM', label: 'Giải tám' },
];

export const DRAW_DURATION_SECONDS = 7;
export const ROLL_INTERVAL_MS = 50;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { PrizeId, DrawingState } from './types';
import { PRIZES, DRAW_DURATION_SECONDS, ROLL_INTERVAL_MS } from './constants';

const App: React.FC = () => {
  const [selectedPrize, setSelectedPrize] = useState<PrizeId>(PRIZES[PRIZES.length - 1].id);
  const [results, setResults] = useState<Record<PrizeId, string[]>>(() => {
    const initial: any = {};
    PRIZES.forEach(p => initial[p.id] = []);
    return initial;
  });
  const [drawState, setDrawState] = useState<DrawingState>({
    isDrawing: false,
    rollingNumber: '00',
    targetPrize: null,
    secondsRemaining: 0
  });

  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const rollingRef = useRef<NodeJS.Timeout | null>(null);

  const startDraw = useCallback(() => {
    if (drawState.isDrawing) return;

    setDrawState({
      isDrawing: true,
      rollingNumber: '00',
      targetPrize: selectedPrize,
      secondsRemaining: DRAW_DURATION_SECONDS
    });

    // Handle rolling numbers
    rollingRef.current = setInterval(() => {
      const randomNum = Math.floor(Math.random() * 100);
      const padded = randomNum.toString().padStart(2, '0');
      setDrawState(prev => ({ ...prev, rollingNumber: padded }));
    }, ROLL_INTERVAL_MS);

    // Handle the countdown and final result
    const startTime = Date.now();
    const endTime = startTime + DRAW_DURATION_SECONDS * 1000;

    const tick = () => {
      const now = Date.now();
      const remaining = Math.max(0, Math.ceil((endTime - now) / 1000));

      setDrawState(prev => ({ ...prev, secondsRemaining: remaining }));

      if (now >= endTime) {
        finishDraw();
      } else {
        timerRef.current = setTimeout(tick, 100);
      }
    };

    timerRef.current = setTimeout(tick, 100);
  }, [selectedPrize, drawState.isDrawing]);

  const finishDraw = useCallback(() => {
    if (rollingRef.current) clearInterval(rollingRef.current);
    if (timerRef.current) clearTimeout(timerRef.current);

    setDrawState(prev => {
      const finalNumber = prev.rollingNumber;
      const prizeId = prev.targetPrize;

      if (prizeId) {
        setResults(oldResults => ({
          ...oldResults,
          [prizeId]: [...oldResults[prizeId], finalNumber]
        }));
      }

      return {
        ...prev,
        isDrawing: false,
        secondsRemaining: 0
      };
    });
  }, []);

  const resetAll = () => {
    if (drawState.isDrawing) return;
    const initial: any = {};
    PRIZES.forEach(p => initial[p.id] = []);
    setResults(initial);
  };

  useEffect(() => {
    return () => {
      if (rollingRef.current) clearInterval(rollingRef.current);
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-gray-50">
      <div className="max-w-3xl w-full bg-white shadow-xl rounded-lg p-8 border border-gray-200">
        <h1 className="text-3xl font-bold text-center mb-8 uppercase tracking-widest text-gray-800">
          Kết Quả Trúng Thưởng
        </h1>

        <div className="overflow-x-auto mb-8">
          <table className="w-full border-collapse border border-gray-300 text-sm md:text-base">
            <thead>
              <tr className="bg-gray-100">
                <th className="border border-gray-300 p-3 text-center w-20">CHỌN</th>
                <th className="border border-gray-300 p-3 text-left w-32 md:w-40">GIẢI</th>
                <th className="border border-gray-300 p-3 text-left">KẾT QUẢ</th>
              </tr>
            </thead>
            <tbody>
              {PRIZES.map((prize) => {
                const isTargeted = drawState.isDrawing && drawState.targetPrize === prize.id;
                const resultText = results[prize.id].join(' - ');

                return (
                  <tr key={prize.id} className="hover:bg-gray-50 transition-colors">
                    <td className="border border-gray-300 p-3 text-center">
                      <input
                        type="radio"
                        name="prizeSelection"
                        checked={selectedPrize === prize.id}
                        onChange={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                        disabled={drawState.isDrawing}
                        className="w-5 h-5 cursor-pointer accent-blue-600"
                      />
                    </td>
                    <td className="border border-gray-300 p-3 font-semibold text-gray-700">
                      {prize.label}
                    </td>
                    <td className="border border-gray-300 p-3 min-h-[44px]">
                      <div className="flex items-center gap-2">
                        <span className="text-lg font-mono tracking-wider break-all">
                          {resultText}
                        </span>
                        {isTargeted && (
                          <div className="flex items-center gap-2">
                            {resultText && <span className="text-gray-400">-</span>}
                            <span className="bg-blue-600 text-white px-2 py-1 rounded text-2xl font-bold animate-pulse font-mono">
                              {drawState.rollingNumber}
                            </span>
                            <span className="text-xs text-blue-500 font-bold ml-1">
                              ({drawState.secondsRemaining}s)
                            </span>
                          </div>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        <div className="flex flex-col gap-4 items-center">
          <button
            onClick={startDraw}
            disabled={drawState.isDrawing}
            className={`
              w-full md:w-64 py-4 px-8 rounded-xl font-bold text-xl uppercase tracking-widest shadow-lg transform active:scale-95 transition-all
              ${drawState.isDrawing 
                ? 'bg-gray-400 cursor-not-allowed text-gray-200' 
                : 'bg-black text-white hover:bg-gray-800 border-2 border-black'}
            `}
          >
            {drawState.isDrawing ? 'Đang quay...' : 'Quay giải'}
          </button>

          <button
            onClick={resetAll}
            disabled={drawState.isDrawing}
            className={`
              w-full md:w-64 py-4 px-8 rounded-xl font-bold text-xl uppercase tracking-widest shadow-md transform active:scale-95 transition-all
              ${drawState.isDrawing 
                ? 'opacity-50 cursor-not-allowed' 
                : 'bg-white text-black border-2 border-black hover:bg-gray-100'}
            `}
          >
            RESET GIẢI
          </button>
        </div>
      </div>

      <p className="mt-8 text-gray-400 text-sm italic">
        * Số ngẫu nhiên từ 00-99. Thời gian quay: 7 giây.
      </p>
    </div>
  );
};

export default App;

