import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { PrizeId, DrawingState } from './types';
import { PRIZES, DRAW_DURATION_SECONDS, ROLL_INTERVAL_MS } from './constants';

const App: React.FC = () => {
  const [selectedPrize, setSelectedPrize] = useState<PrizeId>(PRIZES[PRIZES.length - 1].id);
  const [results, setResults] = useState<Record<PrizeId, string[]>>(() => {
    const initial: any = {};
    PRIZES.forEach(p => initial[p.id] = []);
    return initial;
  });

  const [drawState, setDrawState] = useState<DrawingState & { finalWinner: string | null }>({
    isDrawing: false,
    rollingNumber: '00',
    targetPrize: null,
    secondsRemaining: 0,
    finalWinner: null
  });

  // Lấy danh sách tất cả các số đã trúng thưởng để tránh trùng lặp
  const usedNumbers = useMemo(() => {
    return new Set(Object.values(results).flat());
  }, [results]);

  const timerRef = useRef<any>(null);
  const rollingRef = useRef<any>(null);

  const startDraw = useCallback((duration: number = DRAW_DURATION_SECONDS) => {
    if (drawState.isDrawing) return;

    // Tìm các số chưa được sử dụng (00-99)
    const availableNumbers: string[] = [];
    for (let i = 0; i < 100; i++) {
      const num = i.toString().padStart(2, '0');
      if (!usedNumbers.has(num)) {
        availableNumbers.push(num);
      }
    }

    if (availableNumbers.length === 0) {
      alert("Đã hết số để quay! Vui lòng Reset giải để bắt đầu lại.");
      return;
    }

    // Chọn trước người chiến thắng ngẫu nhiên từ danh sách chưa sử dụng
    const randomIndex = Math.floor(Math.random() * availableNumbers.length);
    const chosenWinner = availableNumbers[randomIndex];

    setDrawState({
      isDrawing: true,
      rollingNumber: '00',
      targetPrize: selectedPrize,
      secondsRemaining: duration,
      finalWinner: chosenWinner
    });

    // Hiệu ứng nhảy số ngẫu nhiên (chỉ mang tính minh họa)
    rollingRef.current = setInterval(() => {
      const randomNum = Math.floor(Math.random() * 100);
      const padded = randomNum.toString().padStart(2, '0');
      setDrawState(prev => ({ ...prev, rollingNumber: padded }));
    }, ROLL_INTERVAL_MS);

    const startTime = Date.now();
    const endTime = startTime + duration * 1000;

    const tick = () => {
      const now = Date.now();
      const remaining = Math.max(0, Math.ceil((endTime - now) / 1000));

      setDrawState(prev => ({ ...prev, secondsRemaining: remaining }));

      if (now >= endTime) {
        finishDraw();
      } else {
        timerRef.current = setTimeout(tick, 100);
      }
    };

    timerRef.current = setTimeout(tick, 100);
  }, [selectedPrize, drawState.isDrawing, usedNumbers]);

  const finishDraw = useCallback(() => {
    if (rollingRef.current) clearInterval(rollingRef.current);
    if (timerRef.current) clearTimeout(timerRef.current);

    setDrawState(prev => {
      const finalNumber = prev.finalWinner || prev.rollingNumber;
      const prizeId = prev.targetPrize;

      if (prizeId) {
        setResults(oldResults => ({
          ...oldResults,
          [prizeId]: [...oldResults[prizeId], finalNumber]
        }));
      }

      return {
        ...prev,
        isDrawing: false,
        rollingNumber: finalNumber, // Hiển thị số cuối cùng chính xác
        secondsRemaining: 0,
        finalWinner: null
      };
    });
  }, []);

  const resetAll = () => {
    if (drawState.isDrawing) return;
    if (window.confirm("Bạn có chắc chắn muốn RESET tất cả kết quả?")) {
      const initial: any = {};
      PRIZES.forEach(p => initial[p.id] = []);
      setResults(initial);
    }
  };

  useEffect(() => {
    return () => {
      if (rollingRef.current) clearInterval(rollingRef.current);
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-slate-100">
      <div className="max-w-3xl w-full bg-white shadow-2xl rounded-2xl p-6 md:p-10 border border-gray-200">
        <header className="mb-8 text-center">
          <h1 className="text-4xl font-extrabold text-red-600 uppercase tracking-tighter drop-shadow-sm">
            Chương Trình Quay Số
          </h1>
          <p className="text-gray-500 font-medium uppercase tracking-widest text-sm mt-1">May Mắn Mỗi Ngày</p>
        </header>

        <div className="overflow-hidden rounded-xl border border-gray-300 shadow-sm mb-8">
          <table className="w-full border-collapse bg-white">
            <thead>
              <tr className="bg-slate-800 text-white">
                <th className="p-4 text-center w-20 border-r border-slate-700">CHỌN</th>
                <th className="p-4 text-left w-32 md:w-40 border-r border-slate-700">GIẢI</th>
                <th className="p-4 text-left">KẾT QUẢ</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {PRIZES.map((prize) => {
                const isTargeted = drawState.isDrawing && drawState.targetPrize === prize.id;
                const prizeResults = results[prize.id];

                return (
                  <tr key={prize.id} className={`transition-colors ${selectedPrize === prize.id ? 'bg-blue-50/50' : 'hover:bg-gray-50'}`}>
                    <td className="p-4 text-center border-r border-gray-200">
                      <div className="flex justify-center">
                        <input
                          type="radio"
                          name="prizeSelection"
                          id={`prize-${prize.id}`}
                          checked={selectedPrize === prize.id}
                          onChange={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                          disabled={drawState.isDrawing}
                          className="w-6 h-6 cursor-pointer accent-blue-600 transition-transform hover:scale-110"
                        />
                      </div>
                    </td>
                    <td className="p-4 font-bold text-gray-800 border-r border-gray-200">
                      <label htmlFor={`prize-${prize.id}`} className="cursor-pointer block w-full">
                        {prize.label}
                      </label>
                    </td>
                    <td className="p-4 min-h-[60px]">
                      <div className="flex flex-wrap items-center gap-2">
                        {prizeResults.map((res, idx) => (
                          <React.Fragment key={idx}>
                            <span className="text-xl font-bold font-mono text-gray-900 bg-gray-100 px-3 py-1 rounded shadow-sm">
                              {res}
