    const chosenWinner = availableNumbers[randomIndex];

    setDrawState(prev => ({
      ...prev,
      isDrawing: true,
      rollingNumber: '00',
      targetPrize: selectedPrize,
      secondsRemaining: duration,
      totalDuration: duration,
      finalWinner: chosenWinner,
      currentProgress: 100
    }));

