      return {
        ...prev,
        isDrawing: false,
        rollingNumber: finalNumber,
        secondsRemaining: 0,
        totalDuration: 0,
        finalWinner: null,
        currentProgress: 0
      };
    });
  }, [playWinSound]);

  const resetAll = () => {
    if (drawState.isDrawing) return;
    initAudio();

    if (window.confirm("BẠN CÓ CHẮC CHẮN MUỐN XÓA TẤT CẢ KẾT QUẢ ĐÃ QUAY?")) {
      const clearedResults: any = {};
      PRIZES.forEach(p => clearedResults[p.id] = []);
      setResults(clearedResults);
      setSelectedPrize(defaultPrizeId);
      setCelebration(null);
      setDrawState({
        isDrawing: false,
        rollingNumber: '00',
        targetPrize: null,
        secondsRemaining: 0,
        totalDuration: 0,
        finalWinner: null,
        currentProgress: 100
      });
    }
  };

  useEffect(() => {
    return () => {
      if (rollingRef.current) clearInterval(rollingRef.current);
      if (timerRef.current) clearTimeout(timerRef.current);
      if (audioContextRef.current) audioContextRef.current.close();
