              <div className="absolute inset-0 bg-amber-400 blur-xl opacity-20 animate-pulse"></div>
              <span className="relative block text-8xl font-black font-mono text-slate-900 border-b-8 border-amber-400 leading-none pb-2">
                {celebration.number}
              </span>
            </div>

            <button
              onClick={() => setCelebration(null)}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-bold text-lg hover:bg-slate-800 transition-colors shadow-lg"
            >
              Tiếp tục
            </button>
          </div>
        </div>
      )}

      <div className="max-w-3xl w-full bg-white shadow-2xl rounded-2xl p-6 md:p-10 border border-gray-200 relative overflow-hidden">

        {/* Progress Bar */}
