                    ? 'Vui lòng nhấn RESET GIẢI bên dưới để bắt đầu một lượt chơi mới.' 
                    : `Chỉ còn lại ${remainingCount} số duy nhất chưa trúng thưởng. Hãy cân nhắc reset sớm.`}
                </p>
              </div>
            </div>
          </div>
        )}

        <div className="overflow-hidden rounded-xl border border-gray-300 shadow-sm mb-8">
          <table className="w-full border-collapse bg-white">
            <thead>
              <tr className="bg-slate-800 text-white">
                <th className="p-4 text-center w-20 border-r border-slate-700">CHỌN</th>
                <th className="p-4 text-left w-32 md:w-40 border-r border-slate-700">GIẢI</th>
                <th className="p-4 text-left">KẾT QUẢ</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {PRIZES.map((prize) => {
                const isSelected = selectedPrize === prize.id;
                const isTargeted = drawState.isDrawing && drawState.targetPrize === prize.id;
                const isWinner = lastSessionWinner?.prizeId === prize.id;
                const prizeResults = results[prize.id];

                return (
                  <tr 
                    key={prize.id} 
                    onClick={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                    className={`transition-all duration-300 cursor-pointer relative group ${
                      isSelected 
                        ? 'bg-blue-50/80 ring-1 ring-blue-100 ring-inset z-10' 
                        : 'hover:bg-gray-50'
                    }`}
                  >
                    <td className={`p-4 text-center border-r border-gray-200 transition-all duration-300 ${
                      isSelected ? 'border-l-[6px] border-l-blue-600 shadow-inner' : 'border-l-[6px] border-l-transparent'
                    }`}>
                      <div 
                        key={isSelected ? `active-${prize.id}` : `inactive-${prize.id}`}
                        className={`flex justify-center ${isSelected ? 'animate-radio-zoom-shake' : ''}`}
                      >
                        <input
                          type="radio"
                          name="prizeSelection"
                          id={`prize-${prize.id}`}
                          checked={isSelected}
                          onChange={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                          disabled={drawState.isDrawing}
                          className="w-6 h-6 cursor-pointer accent-blue-600 transition-transform"
                        />
                      </div>
                    </td>
                    <td className={`p-4 border-r border-gray-200 transition-all ${
                      isSelected || isWinner ? 'font-black' : 'text-gray-700'
                    }`}>
                      <label 
                        key={`${prize.id}-${isSelected}-${isWinner}`}
                        htmlFor={`prize-${prize.id}`} 
                        className={`cursor-pointer block w-full whitespace-nowrap font-bold transition-all duration-300 origin-left ${
                          isWinner 
                            ? 'animate-winner-label-glow text-xl' 
                            : isSelected 
                              ? 'animate-gentle-label-pulse text-lg' 
                              : 'scale-100'
                        }`}
                      >
                        {prize.label}
                      </label>
                    </td>
                    <td className="p-4 min-h-[70px]">
                      <div className={`flex flex-wrap items-center gap-2 transition-transform duration-300 origin-left ${
                        isSelected ? 'scale-[1.02]' : 'scale-100'
                      }`}>
                        {prizeResults.map((res, idx) => {
                          const isLastWinner = lastSessionWinner?.prizeId === prize.id && idx === prizeResults.length - 1;
                          return (
                            <React.Fragment key={`${prize.id}-${res}-${idx}`}>
                              <span className={`text-xl font-bold font-mono text-gray-900 bg-white border border-gray-200 px-3 py-1 rounded shadow-sm animate-pop-in ${
                                isLastWinner ? 'animate-result-shake ring-2 ring-red-500 ring-offset-1 border-red-500' : ''
                              }`}>
                                {res}
                              </span>
                              {idx < prizeResults.length - 1 && <span className="text-gray-400 font-bold">-</span>}
                            </React.Fragment>
                          );
                        })}

                        {isTargeted && (
                          <div className="flex items-center gap-4 ml-4">
                            {prizeResults.length > 0 && <span className="text-gray-400 font-bold">-</span>}
                            <div className="relative flex items-center justify-center p-1">
                              <svg className="w-20 h-20 transform -rotate-90">
                                <circle cx="40" cy="40" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-100" />
                                <circle
                                  cx="40" cy="40" r={radius}
                                  stroke="currentColor" strokeWidth="6" fill="transparent"
                                  strokeDasharray={circumference}
                                  strokeDashoffset={dashOffset}
                                  strokeLinecap="round"
                                  className={`transition-all duration-100 ease-linear shadow-sm ${
                                    isDanger ? 'text-red-500' : drawState.totalDuration <= 3 ? 'text-orange-500' : 'text-blue-600'
                                  }`}
                                />
                              </svg>
                              <div className="absolute inset-0 flex flex-col items-center justify-center">
                                <span className={`text-[11px] font-black leading-none mb-0.5 transition-colors duration-300 ${isDanger ? 'text-red-600 animate-pulse' : 'text-gray-400'}`}>
                                  {drawState.secondsRemaining}s
                                </span>
                                <span className={`text-3xl font-black font-mono leading-none drop-shadow-sm transition-all duration-300 ${isDanger ? 'text-red-600 scale-125' : 'text-red-500 scale-110'} ${drawState.isDrawing ? 'animate-pulse' : ''}`}>
                                  {drawState.rollingNumber}
                                </span>
                              </div>
                            </div>
                          </div>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {/* MAIN HUD COUNTDOWN (NEW VISUAL TIMER) */}
        {drawState.isDrawing && (
          <div className="mb-6 flex flex-col items-center justify-center animate-in zoom-in-95 duration-500">
            <div className="relative flex items-center justify-center">
              {/* Background HUD Pulse */}
              <div className={`absolute inset-0 rounded-full opacity-10 animate-ping ${isDanger ? 'bg-red-600' : 'bg-blue-600'}`}></div>

              <svg className="w-32 h-32 transform -rotate-90">
                <circle cx="64" cy="64" r={hudRadius} stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-100" />
                <circle
                  cx="64" cy="64" r={hudRadius}
                  stroke="currentColor" strokeWidth="8" fill="transparent"
                  strokeDasharray={hudCircumference}
                  strokeDashoffset={hudDashOffset}
                  strokeLinecap="round"
                  className={`transition-all duration-150 ease-linear ${
                    isDanger ? 'text-red-600' : drawState.totalDuration <= 3 ? 'text-orange-500' : 'text-blue-600'
                  }`}
                />
              </svg>

              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <div 
                  key={drawState.secondsRemaining} 
                  className={`text-5xl font-black font-mono tracking-tighter animate-in zoom-in-125 duration-300 
                    ${isDanger ? 'text-red-600' : 'text-slate-900'} 
                    ${isUrgent ? 'animate-subtle-bounce' : ''}`
                  }
                >
                  {drawState.secondsRemaining}
                </div>
                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-[-4px]">giây còn lại</div>
              </div>
            </div>
            <div className="mt-2 text-center">
              <span className="text-xs font-black uppercase tracking-tighter text-slate-500">
                đang xác định người thắng cuộc...
              </span>
            </div>
          </div>
        )}

        <div className="mb-6 bg-slate-50 p-6 rounded-2xl border border-slate-200">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-blue-100 rounded-xl text-blue-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div>
                <h4 className="text-slate-900 font-black text-sm uppercase tracking-tight">Thời gian quay số</h4>
                <p className="text-slate-500 text-xs font-medium">Kéo để điều chỉnh tốc độ</p>
              </div>
            </div>

            <div className="flex-1 max-w-md flex items-center gap-6">
              <input
                type="range"
                min="3"
                max="15"
                step="1"
                value={drawDuration}
                onChange={(e) => setDrawDuration(parseInt(e.target.value))}
                disabled={drawState.isDrawing}
                className="flex-1 h-2.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 disabled:opacity-50 disabled:cursor-not-allowed"
              />
              <div className="min-w-[70px] bg-white border-2 border-blue-600 rounded-xl px-3 py-1.5 text-center shadow-sm">
                <span className="text-blue-700 font-black text-xl">{drawDuration}</span>
                <span className="text-blue-600 font-bold text-xs ml-0.5">S</span>
              </div>
            </div>
          </div>
        </div>

        <div className="flex flex-col gap-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <button
              onClick={() => startDraw(drawDuration)}
              disabled={drawState.isDrawing || remainingCount === 0}
              className={`
                relative py-5 px-6 rounded-2xl font-black text-xl uppercase tracking-widest shadow-xl transform active:scale-95 transition-all
                ${drawState.isDrawing || remainingCount === 0
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed border-none' 
                  : 'bg-gradient-to-r from-blue-600 to-blue-700 text-white hover:from-blue-700 hover:to-blue-800 border-b-4 border-blue-900'}
              `}
            >
              {drawState.isDrawing && drawState.totalDuration === drawDuration ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Đang quay...
                </span>
              ) : `Bắt đầu quay (${drawDuration}s)`}
            </button>

            <button
              onClick={() => startDraw(3)}
              disabled={drawState.isDrawing || remainingCount === 0}
              className={`
                relative py-5 px-6 rounded-2xl font-black text-xl uppercase tracking-widest shadow-xl transform active:scale-95 transition-all
                ${drawState.isDrawing || remainingCount === 0
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed border-none' 
                  : 'bg-gradient-to-r from-amber-500 to-orange-600 text-white hover:from-amber-600 hover:to-orange-700 border-b-4 border-orange-800'}
              `}
            >
              {drawState.isDrawing && drawState.totalDuration === 3 ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Quay nhanh...
                </span>
              ) : 'Quay Nhanh (3s)'}
            </button>
          </div>

          <button
            onClick={() => setShowResetConfirm(true)}
            disabled={drawState.isDrawing}
            className={`
              w-full py-4 rounded-2xl font-black text-xl uppercase tracking-widest shadow-lg transform active:scale-95 transition-all
              ${drawState.isDrawing 
                ? 'opacity-40 cursor-not-allowed' 
                : 'bg-white text-red-600 border-2 border-red-600 hover:bg-red-50'}
            `}
          >
            RESET GIẢI
          </button>
        </div>

        <div className="mt-8 flex flex-col gap-3">
          <div className="flex flex-wrap justify-between items-center text-xs font-bold uppercase text-gray-500 tracking-wider">
            <div className="flex gap-4">
              <span className="flex items-center gap-1.5">
                <span className="w-2 h-2 rounded-full bg-green-500"></span>
                CÒN LẠI: <span key={remainingCount} className={`text-slate-900 inline-block transition-all ${drawState.isDrawing ? '' : 'animate-subtle-bounce'}`}>{remainingCount}/100</span>
              </span>
              <span className="flex items-center gap-1.5">
                <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                ĐÃ DÙNG: <span key={usedNumbers.size} className={`text-slate-900 inline-block transition-all ${drawState.isDrawing ? '' : 'animate-subtle-bounce'}`}>{usedNumbers.size}/100</span>
              </span>
            </div>
            <div className="mt-1 sm:mt-0 text-[10px] text-gray-400 font-medium">CHẾ ĐỘ: KHÔNG TRÙNG LẶP</div>
          </div>
        </div>
      </div>

      <p className="mt-6 text-gray-400 text-xs text-center max-w-md px-4">
        Hệ thống tự động loại bỏ các số đã trúng thưởng. Kết quả hiển thị tại cột 3 và được lưu trữ liên tục. 
        Nhấn RESET để xóa sạch kết quả.
      </p>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { PrizeId, DrawingState } from './types';
import { PRIZES, DRAW_DURATION_SECONDS, ROLL_INTERVAL_MS } from './constants';

const App: React.FC = () => {
  const defaultPrizeId = PRIZES[PRIZES.length - 1].id;
  const [selectedPrize, setSelectedPrize] = useState<PrizeId>(defaultPrizeId);
  const [drawDuration, setDrawDuration] = useState<number>(DRAW_DURATION_SECONDS);

  const [results, setResults] = useState<Record<PrizeId, string[]>>(() => {
    const initial: any = {};
    PRIZES.forEach(p => initial[p.id] = []);
    return initial;
  });

  const [drawState, setDrawState] = useState<DrawingState & { finalWinner: string | null; currentProgress: number }>({
    isDrawing: false,
    rollingNumber: '00',
    targetPrize: null,
    secondsRemaining: 0,
    totalDuration: 0,
    finalWinner: null,
    currentProgress: 100
  });

  const [celebration, setCelebration] = useState<{ prizeLabel: string, number: string } | null>(null);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [lastSessionWinner, setLastSessionWinner] = useState<{ prizeId: PrizeId, number: string } | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  const playClickSound = useCallback(() => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(150, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.05, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.005, ctx.currentTime + 0.1);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.1);
  }, []);

  const playWinSound = useCallback(() => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;

    const playNote = (freq: number, startTime: number, duration: number) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(freq, startTime);
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start(startTime);
      osc.stop(startTime + duration);
    };

    const now = ctx.currentTime;
    playNote(523.25, now, 0.4); 
    playNote(659.25, now + 0.1, 0.4); 
    playNote(783.99, now + 0.2, 0.6); 
    playNote(1046.50, now + 0.35, 0.8);
  }, []);

  const usedNumbers = useMemo(() => {
    return new Set(Object.values(results).flat());
  }, [results]);

  const remainingCount = 100 - usedNumbers.size;

  const timerRef = useRef<any>(null);
  const rollingRef = useRef<any>(null);

  const startDraw = useCallback((duration: number) => {
    if (drawState.isDrawing) return;
    initAudio();
    setCelebration(null);
    setLastSessionWinner(null);

    const availableNumbers: string[] = [];
    for (let i = 0; i < 100; i++) {
      const num = i.toString().padStart(2, '0');
      if (!usedNumbers.has(num)) {
        availableNumbers.push(num);
      }
    }

    if (availableNumbers.length === 0) {
      alert("Đã hết số để quay! Vui lòng Reset giải để bắt đầu lại.");
      return;
    }

    const randomIndex = Math.floor(Math.random() * availableNumbers.length);
    const chosenWinner = availableNumbers[randomIndex];

    setDrawState(prev => ({
      ...prev,
      isDrawing: true,
      rollingNumber: '00',
      targetPrize: selectedPrize,
      secondsRemaining: duration,
      totalDuration: duration,
      finalWinner: chosenWinner,
      currentProgress: 100
    }));

    rollingRef.current = setInterval(() => {
      const randomNum = Math.floor(Math.random() * 100);
      const padded = randomNum.toString().padStart(2, '0');
      setDrawState(prev => ({ ...prev, rollingNumber: padded }));
      playClickSound();
    }, ROLL_INTERVAL_MS);

    const startTime = Date.now();
    const endTime = startTime + duration * 1000;

    const tick = () => {
      const now = Date.now();
      const remainingMs = Math.max(0, endTime - now);
      const remainingSecs = Math.ceil(remainingMs / 1000);
      const progress = (remainingMs / (duration * 1000)) * 100;

      setDrawState(prev => ({ 
        ...prev, 
        secondsRemaining: remainingSecs,
        currentProgress: progress
      }));

      if (now >= endTime) {
        finishDraw();
      } else {
        timerRef.current = setTimeout(tick, 30);
      }
    };

    timerRef.current = setTimeout(tick, 30);
  }, [selectedPrize, drawState.isDrawing, usedNumbers, playClickSound]);

  const finishDraw = useCallback(() => {
    if (rollingRef.current) clearInterval(rollingRef.current);
    if (timerRef.current) clearTimeout(timerRef.current);
    playWinSound();

    setDrawState(prev => {
      const finalNumber = prev.finalWinner || prev.rollingNumber;
      const prizeId = prev.targetPrize;
      const prizeLabel = PRIZES.find(p => p.id === prizeId)?.label || "Giải thưởng";

      if (prizeId) {
        setResults(oldResults => ({
          ...oldResults,
          [prizeId]: [...oldResults[prizeId], finalNumber]
        }));

        setLastSessionWinner({ prizeId, number: finalNumber });
        setCelebration({ prizeLabel, number: finalNumber });
      }

      return {
        ...prev,
        isDrawing: false,
        rollingNumber: finalNumber,
        secondsRemaining: 0,
        totalDuration: 0,
        finalWinner: null,
        currentProgress: 0
      };
    });
  }, [playWinSound]);

  const handleActualReset = () => {
    initAudio();
    const clearedResults: any = {};
    PRIZES.forEach(p => clearedResults[p.id] = []);
    setResults(clearedResults);
    setSelectedPrize(defaultPrizeId);
    setCelebration(null);
    setLastSessionWinner(null);
    setShowResetConfirm(false);
    setDrawState({
      isDrawing: false,
      rollingNumber: '00',
      targetPrize: null,
      secondsRemaining: 0,
      totalDuration: 0,
      finalWinner: null,
      currentProgress: 100
    });
  };

  const handleDrawAgain = () => {
    setCelebration(null);
    setTimeout(() => {
      startDraw(drawDuration);
    }, 300);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && showResetConfirm) {
        setShowResetConfirm(false);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [showResetConfirm]);

  useEffect(() => {
    return () => {
      if (rollingRef.current) clearInterval(rollingRef.current);
      if (timerRef.current) clearTimeout(timerRef.current);
      if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  const radius = 28;
  const circumference = 2 * Math.PI * radius;
  const dashOffset = circumference - (drawState.currentProgress / 100) * circumference;

  // Larger circle for the HUD
  const hudRadius = 40;
  const hudCircumference = 2 * Math.PI * hudRadius;
  const hudDashOffset = hudCircumference - (drawState.currentProgress / 100) * hudCircumference;

  const isDanger = drawState.secondsRemaining <= 2 && drawState.isDrawing;
  const isUrgent = drawState.secondsRemaining <= 5 && drawState.isDrawing;
  const activePrizeLabel = PRIZES.find(p => p.id === drawState.targetPrize)?.label;

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-slate-100 relative">

      {/* GLOBAL COUNTDOWN PROGRESS BAR */}
      <div className={`fixed top-0 left-0 w-full h-1.5 z-[200] transition-opacity duration-300 ${drawState.isDrawing ? 'opacity-100' : 'opacity-0'}`}>
        <div 
          className={`h-full transition-all duration-75 ease-linear shadow-[0_0_10px_rgba(37,99,235,0.5)] ${isDanger ? 'bg-red-500' : 'bg-blue-600'}`}
          style={{ width: `${drawState.currentProgress}%` }}
        ></div>
      </div>

      {/* Reset Confirmation Modal */}
      {showResetConfirm && (
        <div 
          className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300"
          onClick={() => setShowResetConfirm(false)}
        >
          <div 
            className="bg-white rounded-[2rem] p-8 max-w-sm w-full shadow-2xl animate-in zoom-in-95 duration-200"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mb-6">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <h3 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Xóa tất cả kết quả?</h3>
              <p className="text-slate-500 mb-8 leading-relaxed">
                Hành động này sẽ xóa sạch danh sách trúng thưởng và các số đã quay. Bạn không thể hoàn tác thao tác này.
              </p>
              <div className="flex flex-col gap-3 w-full">
                <button
                  onClick={handleActualReset}
                  className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 transition-all shadow-lg active:scale-95"
                >
                  XÁC NHẬN RESET
                </button>
                <button
                  onClick={() => setShowResetConfirm(false)}
                  className="w-full py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors"
                >
                  HỦY BỎ
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Celebration Overlay */}
      {celebration && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-500">
          <div className="bg-white rounded-[2rem] p-10 max-md w-full shadow-[0_0_50px_rgba(255,255,255,0.2)] text-center relative overflow-hidden animate-in zoom-in-90 slide-in-from-bottom-10 duration-500">
            {[...Array(20)].map((_, i) => (
              <div 
                key={i} 
                className="absolute w-3 h-3 rounded-sm opacity-60 pointer-events-none"
                style={{
                  backgroundColor: ['#ef4444', '#3b82f6', '#f59e0b', '#10b981', '#8b5cf6'][i % 5],
                  top: '-20px',
                  left: `${Math.random() * 100}%`,
                  animation: `fall ${1.5 + Math.random() * 2}s linear infinite`,
                  animationDelay: `${Math.random() * 2}s`,
                  transform: `rotate(${Math.random() * 360}deg)`
                }}
              />
            ))}
            <div className="mb-6 flex justify-center">
              <div className="w-20 h-20 bg-amber-100 rounded-full flex items-center justify-center animate-bounce">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-7.714 2.143L11 21l-2.286-6.857L1 12l7.714-2.143L11 3z" />
                </svg>
              </div>
            </div>
            <h2 className="text-4xl font-black bg-clip-text text-transparent bg-gradient-to-r from-red-600 to-orange-500 mb-2 uppercase tracking-tighter">
              THẮNG GIẢI!
            </h2>
            <p className="text-slate-500 font-bold mb-8 text-xl uppercase tracking-widest">{celebration.prizeLabel}</p>
            <div className="mb-10 relative inline-block group">
              <div className="absolute inset-0 bg-amber-400 blur-2xl opacity-30 group-hover:opacity-50 transition-opacity animate-pulse"></div>
              <span className="relative block text-9xl font-black font-mono text-slate-900 border-b-[12px] border-amber-400 leading-none pb-4 tracking-tighter">
                {celebration.number}
              </span>
            </div>
            <div className="flex flex-col sm:flex-row gap-3 w-full">
              <button
                onClick={() => setCelebration(null)}
                className="flex-1 py-4 bg-slate-200 text-slate-800 rounded-2xl font-black text-lg hover:bg-slate-300 transition-all shadow-md active:scale-95"
              >
                CHẤP NHẬN
              </button>
              <button
                onClick={handleDrawAgain}
                disabled={remainingCount === 0}
                className={`flex-1 py-4 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-2xl font-black text-lg hover:from-blue-700 hover:to-blue-800 transition-all shadow-xl hover:shadow-2xl active:scale-95 border-b-4 border-blue-900 ${remainingCount === 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                QUAY LẠI
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="max-w-4xl w-full bg-white shadow-2xl rounded-2xl p-6 md:p-10 border border-gray-200 relative overflow-hidden">

        {drawState.isDrawing && (
          <div className={`absolute top-0 left-0 w-full p-3 text-center animate-in slide-in-from-top-full duration-500 flex items-center justify-center gap-4 border-b ${isDanger ? 'bg-red-50 border-red-200' : 'bg-blue-50 border-blue-200'}`}>
            <div className="flex items-center gap-2">
              <span className={`w-3 h-3 rounded-full ${isDanger ? 'bg-red-600 animate-ping' : 'bg-blue-600 animate-pulse'}`}></span>
              <span className={`text-sm font-black uppercase tracking-widest ${isDanger ? 'text-red-700' : 'text-blue-700'}`}>
                Đang quay {activePrizeLabel}
              </span>
            </div>
            <div className={`px-4 py-1 rounded-full font-black text-lg border-2 shadow-sm transition-all duration-300 ${isDanger ? 'bg-red-600 text-white border-red-700 animate-bounce' : 'bg-white text-blue-600 border-blue-600'}`}>
              {drawState.secondsRemaining}s
            </div>
          </div>
        )}

        <header className={`mb-8 text-center transition-all duration-500 ${drawState.isDrawing ? 'pt-10' : ''}`}>
          <h1 className="text-4xl font-extrabold text-red-600 uppercase tracking-tighter drop-shadow-sm">
            Chương Trình Quay Số
          </h1>
          <p className="text-gray-500 font-medium uppercase tracking-widest text-sm mt-1">May Mắn Mỗi Ngày</p>
        </header>

        {remainingCount < 5 && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-4 border-2 shadow-lg animate-in slide-in-from-top-4 duration-500 ${
            remainingCount === 0 
              ? 'bg-red-50 border-red-500 text-red-700 animate-pulse' 
              : 'bg-amber-50 border-amber-400 text-amber-800'
          }`}>
            <div className={`p-2 rounded-full ${remainingCount === 0 ? 'bg-red-100 text-red-600' : 'bg-amber-100 text-amber-600'}`}>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <div className="flex-1">
              <h4 className="font-black text-lg uppercase tracking-tight">
                {remainingCount === 0 ? 'Đã hết số quay duy nhất!' : 'Sắp hết số quay!'}
              </h4>
              <div key={remainingCount} className={remainingCount < 5 ? 'animate-subtle-bounce' : ''}>
                <p className="text-sm font-medium opacity-80 leading-tight">
                  {remainingCount === 0 
                    ? 'Vui lòng nhấn RESET GIẢI bên dưới để bắt đầu một lượt chơi mới.' 
                    : `Chỉ còn lại ${remainingCount} số duy nhất chưa trúng thưởng. Hãy cân nhắc reset sớm.`}
                </p>
              </div>
            </div>
          </div>
        )}

        <div className="overflow-hidden rounded-xl border border-gray-300 shadow-sm mb-8">
          <table className="w-full border-collapse bg-white">
            <thead>
              <tr className="bg-slate-800 text-white">
                <th className="p-4 text-center w-20 border-r border-slate-700">CHỌN</th>
                <th className="p-4 text-left w-32 md:w-40 border-r border-slate-700">GIẢI</th>
                <th className="p-4 text-left">KẾT QUẢ</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {PRIZES.map((prize) => {
                const isSelected = selectedPrize === prize.id;
                const isTargeted = drawState.isDrawing && drawState.targetPrize === prize.id;
                const isWinner = lastSessionWinner?.prizeId === prize.id;
                const prizeResults = results[prize.id];

                return (
                  <tr 
                    key={prize.id} 
                    onClick={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                    className={`transition-all duration-300 cursor-pointer relative group ${
                      isSelected 
                        ? 'bg-blue-50/80 ring-1 ring-blue-100 ring-inset z-10' 
                        : 'hover:bg-gray-50'
                    }`}
                  >
                    <td className={`p-4 text-center border-r border-gray-200 transition-all duration-300 ${
                      isSelected ? 'border-l-[6px] border-l-blue-600 shadow-inner' : 'border-l-[6px] border-l-transparent'
                    }`}>
                      <div 
                        key={isSelected ? `active-${prize.id}` : `inactive-${prize.id}`}
                        className={`flex justify-center ${isSelected ? 'animate-radio-zoom-shake' : ''}`}
                      >
                        <input
                          type="radio"
                          name="prizeSelection"
                          id={`prize-${prize.id}`}
                          checked={isSelected}
                          onChange={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                          disabled={drawState.isDrawing}
                          className="w-6 h-6 cursor-pointer accent-blue-600 transition-transform"
                        />
                      </div>
                    </td>
                    <td className={`p-4 border-r border-gray-200 transition-all ${
                      isSelected || isWinner ? 'font-black' : 'text-gray-700'
                    }`}>
                      <label 
                        key={`${prize.id}-${isSelected}-${isWinner}`}
                        htmlFor={`prize-${prize.id}`} 
                        className={`cursor-pointer block w-full whitespace-nowrap font-bold transition-all duration-300 origin-left ${
                          isWinner 
                            ? 'animate-winner-label-glow text-xl' 
                            : isSelected 
                              ? 'animate-gentle-label-pulse text-lg' 
                              : 'scale-100'
                        }`}
                      >
                        {prize.label}
                      </label>
                    </td>
                    <td className="p-4 min-h-[70px]">
                      <div className={`flex flex-wrap items-center gap-2 transition-transform duration-300 origin-left ${
                        isSelected ? 'scale-[1.02]' : 'scale-100'
                      }`}>
                        {prizeResults.map((res, idx) => {
                          const isLastWinner = lastSessionWinner?.prizeId === prize.id && idx === prizeResults.length - 1;
                          return (
                            <React.Fragment key={`${prize.id}-${res}-${idx}`}>
                              <span className={`text-xl font-bold font-mono text-gray-900 bg-white border border-gray-200 px-3 py-1 rounded shadow-sm animate-pop-in ${
                                isLastWinner ? 'animate-highlight-vibrate ring-2 ring-red-500 ring-offset-1 border-red-500' : ''
                              }`}>
                                {res}
                              </span>
                              {idx < prizeResults.length - 1 && <span className="text-gray-400 font-bold">-</span>}
                            </React.Fragment>
                          );
                        })}

                        {isTargeted && (
                          <div className="flex items-center gap-4 ml-4">
                            {prizeResults.length > 0 && <span className="text-gray-400 font-bold">-</span>}
                            <div className="relative flex items-center justify-center p-1">
                              <svg className="w-20 h-20 transform -rotate-90">
                                <circle cx="40" cy="40" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-100" />
                                <circle
                                  cx="40" cy="40" r={radius}
                                  stroke="currentColor" strokeWidth="6" fill="transparent"
                                  strokeDasharray={circumference}
                                  strokeDashoffset={dashOffset}
                                  strokeLinecap="round"
                                  className={`transition-all duration-100 ease-linear shadow-sm ${
                                    isDanger ? 'text-red-500' : drawState.totalDuration <= 3 ? 'text-orange-500' : 'text-blue-600'
                                  }`}
                                />
                              </svg>
                              <div className="absolute inset-0 flex flex-col items-center justify-center">
                                <span className={`text-[11px] font-black leading-none mb-0.5 transition-colors duration-300 ${isDanger ? 'text-red-600 animate-pulse' : 'text-gray-400'}`}>
                                  {drawState.secondsRemaining}s
                                </span>
                                <span className={`text-3xl font-black font-mono leading-none drop-shadow-sm transition-all duration-300 ${isDanger ? 'text-red-600 scale-125' : 'text-red-500 scale-110'} ${drawState.isDrawing ? 'animate-pulse' : ''}`}>
                                  {drawState.rollingNumber}
                                </span>
                              </div>
                            </div>
                          </div>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {/* MAIN HUD COUNTDOWN (NEW VISUAL TIMER) */}
        {drawState.isDrawing && (
          <div className="mb-6 flex flex-col items-center justify-center animate-in zoom-in-95 duration-500">
            <div className="relative flex items-center justify-center">
              {/* Background HUD Pulse */}
              <div className={`absolute inset-0 rounded-full opacity-10 animate-ping ${isDanger ? 'bg-red-600' : 'bg-blue-600'}`}></div>

              <svg className="w-32 h-32 transform -rotate-90">
                <circle cx="64" cy="64" r={hudRadius} stroke="currentColor" strokeWidth="8" fill="transparent" className="text-slate-100" />
                <circle
                  cx="64" cy="64" r={hudRadius}
                  stroke="currentColor" strokeWidth="8" fill="transparent"
                  strokeDasharray={hudCircumference}
                  strokeDashoffset={hudDashOffset}
                  strokeLinecap="round"
                  className={`transition-all duration-150 ease-linear ${
                    isDanger ? 'text-red-600' : drawState.totalDuration <= 3 ? 'text-orange-500' : 'text-blue-600'
                  }`}
                />
              </svg>

              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <div 
                  key={drawState.secondsRemaining} 
                  className={`text-5xl font-black font-mono tracking-tighter animate-in zoom-in-125 duration-300 
                    ${isDanger ? 'text-red-600' : 'text-slate-900'} 
                    ${isUrgent ? 'animate-subtle-bounce' : ''}`
                  }
                >
                  {drawState.secondsRemaining}
                </div>
                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-[-4px]">giây còn lại</div>
              </div>
            </div>
            <div className="mt-2 text-center">
              <span className="text-xs font-black uppercase tracking-tighter text-slate-500">
                đang xác định người thắng cuộc...
              </span>
            </div>
          </div>
        )}

        <div className="mb-6 bg-slate-50 p-6 rounded-2xl border border-slate-200">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-blue-100 rounded-xl text-blue-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div>
                <h4 className="text-slate-900 font-black text-sm uppercase tracking-tight">Thời gian quay số</h4>
                <p className="text-slate-500 text-xs font-medium">Kéo để điều chỉnh tốc độ</p>
              </div>
            </div>

            <div className="flex-1 max-w-md flex items-center gap-6">
              <input
                type="range"
                min="3"
                max="15"
                step="1"
                value={drawDuration}
                onChange={(e) => setDrawDuration(parseInt(e.target.value))}
                disabled={drawState.isDrawing}
                className="flex-1 h-2.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 disabled:opacity-50 disabled:cursor-not-allowed"
              />
              <div className="min-w-[70px] bg-white border-2 border-blue-600 rounded-xl px-3 py-1.5 text-center shadow-sm">
                <span className="text-blue-700 font-black text-xl">{drawDuration}</span>
                <span className="text-blue-600 font-bold text-xs ml-0.5">S</span>
              </div>
            </div>
          </div>
        </div>

        <div className="flex flex-col gap-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <button
              onClick={() => startDraw(drawDuration)}
              disabled={drawState.isDrawing || remainingCount === 0}
              className={`
                relative py-5 px-6 rounded-2xl font-black text-xl uppercase tracking-widest shadow-xl transform active:scale-95 transition-all
                ${drawState.isDrawing || remainingCount === 0
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed border-none' 
                  : 'bg-gradient-to-r from-blue-600 to-blue-700 text-white hover:from-blue-700 hover:to-blue-800 border-b-4 border-blue-900'}
              `}
            >
              {drawState.isDrawing && drawState.totalDuration === drawDuration ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Đang quay...
                </span>
              ) : `Bắt đầu quay (${drawDuration}s)`}
            </button>

            <button
              onClick={() => startDraw(3)}
              disabled={drawState.isDrawing || remainingCount === 0}
              className={`
                relative py-5 px-6 rounded-2xl font-black text-xl uppercase tracking-widest shadow-xl transform active:scale-95 transition-all
                ${drawState.isDrawing || remainingCount === 0
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed border-none' 
                  : 'bg-gradient-to-r from-amber-500 to-orange-600 text-white hover:from-amber-600 hover:to-orange-700 border-b-4 border-orange-800'}
              `}
            >
              {drawState.isDrawing && drawState.totalDuration === 3 ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Quay nhanh...
                </span>
              ) : 'Quay Nhanh (3s)'}
            </button>
          </div>

          <button
            onClick={() => setShowResetConfirm(true)}
            disabled={drawState.isDrawing}
            className={`
              w-full py-4 rounded-2xl font-black text-xl uppercase tracking-widest shadow-lg transform active:scale-95 transition-all
              ${drawState.isDrawing 
                ? 'opacity-40 cursor-not-allowed' 
                : 'bg-white text-red-600 border-2 border-red-600 hover:bg-red-50'}
            `}
          >
            RESET GIẢI
          </button>
        </div>

        <div className="mt-8 flex flex-col gap-3">
          <div className="flex flex-wrap justify-between items-center text-xs font-bold uppercase text-gray-500 tracking-wider">
            <div className="flex gap-4">
              <span className="flex items-center gap-1.5">
                <span className="w-2 h-2 rounded-full bg-green-500"></span>
                CÒN LẠI: <span key={remainingCount} className={`text-slate-900 inline-block transition-all ${drawState.isDrawing ? '' : 'animate-subtle-bounce'}`}>{remainingCount}/100</span>
              </span>
              <span className="flex items-center gap-1.5">
                <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                ĐÃ DÙNG: <span key={usedNumbers.size} className={`text-slate-900 inline-block transition-all ${drawState.isDrawing ? '' : 'animate-subtle-bounce'}`}>{usedNumbers.size}/100</span>
              </span>
            </div>
            <div className="mt-1 sm:mt-0 text-[10px] text-gray-400 font-medium">CHẾ ĐỘ: KHÔNG TRÙNG LẶP</div>
          </div>
        </div>
      </div>

      <p className="mt-6 text-gray-400 text-xs text-center max-w-md px-4">
        Hệ thống tự động loại bỏ các số đã trúng thưởng. Kết quả hiển thị tại cột 3 và được lưu trữ liên tục. 
        Nhấn RESET để xóa sạch kết quả.
      </p>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { PrizeId, DrawingState } from './types';
import { PRIZES, DRAW_DURATION_SECONDS, ROLL_INTERVAL_MS } from './constants';

const App: React.FC = () => {
  const defaultPrizeId = PRIZES[PRIZES.length - 1].id;
  const [selectedPrize, setSelectedPrize] = useState<PrizeId>(defaultPrizeId);
  const [drawDuration, setDrawDuration] = useState<number>(DRAW_DURATION_SECONDS);

  const [results, setResults] = useState<Record<PrizeId, string[]>>(() => {
    const initial: any = {};
    PRIZES.forEach(p => initial[p.id] = []);
    return initial;
  });

  const [drawState, setDrawState] = useState<DrawingState & { finalWinner: string | null; currentProgress: number }>({
    isDrawing: false,
    rollingNumber: '00',
    targetPrize: null,
    secondsRemaining: 0,
    totalDuration: 0,
    finalWinner: null,
    currentProgress: 100
  });

  const [celebration, setCelebration] = useState<{ prizeLabel: string, number: string } | null>(null);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [lastSessionWinner, setLastSessionWinner] = useState<{ prizeId: PrizeId, number: string } | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  const playClickSound = useCallback(() => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(150, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.05, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.005, ctx.currentTime + 0.1);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.1);
  }, []);

  const playWinSound = useCallback(() => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;

    const playNote = (freq: number, startTime: number, duration: number) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(freq, startTime);
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start(startTime);
      osc.stop(startTime + duration);
    };

    const now = ctx.currentTime;
    playNote(523.25, now, 0.4); 
    playNote(659.25, now + 0.1, 0.4); 
    playNote(783.99, now + 0.2, 0.6); 
    playNote(1046.50, now + 0.35, 0.8);
  }, []);

  const usedNumbers = useMemo(() => {
    return new Set(Object.values(results).flat());
  }, [results]);

  const remainingCount = 100 - usedNumbers.size;

  const timerRef = useRef<any>(null);
  const rollingRef = useRef<any>(null);

  const startDraw = useCallback((duration: number) => {
    if (drawState.isDrawing) return;
    initAudio();
    setCelebration(null);
    setLastSessionWinner(null);

    const availableNumbers: string[] = [];
    for (let i = 0; i < 100; i++) {
      const num = i.toString().padStart(2, '0');
      if (!usedNumbers.has(num)) {
        availableNumbers.push(num);
      }
    }

    if (availableNumbers.length === 0) {
      alert("Đã hết số để quay! Vui lòng Reset giải để bắt đầu lại.");
      return;
    }

    const randomIndex = Math.floor(Math.random() * availableNumbers.length);
    const chosenWinner = availableNumbers[randomIndex];

    setDrawState(prev => ({
      ...prev,
      isDrawing: true,
      rollingNumber: '00',
      targetPrize: selectedPrize,
      secondsRemaining: duration,
      totalDuration: duration,
      finalWinner: chosenWinner,
      currentProgress: 100
    }));

    rollingRef.current = setInterval(() => {
      const randomNum = Math.floor(Math.random() * 100);
      const padded = randomNum.toString().padStart(2, '0');
      setDrawState(prev => ({ ...prev, rollingNumber: padded }));
      playClickSound();
    }, ROLL_INTERVAL_MS);

    const startTime = Date.now();
    const endTime = startTime + duration * 1000;

    const tick = () => {
      const now = Date.now();
      const remainingMs = Math.max(0, endTime - now);
      const remainingSecs = Math.ceil(remainingMs / 1000);
      const progress = (remainingMs / (duration * 1000)) * 100;

      setDrawState(prev => ({ 
        ...prev, 
        secondsRemaining: remainingSecs,
        currentProgress: progress
      }));

      if (now >= endTime) {
        finishDraw();
      } else {
        timerRef.current = setTimeout(tick, 30);
      }
    };

    timerRef.current = setTimeout(tick, 30);
  }, [selectedPrize, drawState.isDrawing, usedNumbers, playClickSound]);

  const finishDraw = useCallback(() => {
    if (rollingRef.current) clearInterval(rollingRef.current);
    if (timerRef.current) clearTimeout(timerRef.current);
    playWinSound();

    setDrawState(prev => {
      const finalNumber = prev.finalWinner || prev.rollingNumber;
      const prizeId = prev.targetPrize;
      const prizeLabel = PRIZES.find(p => p.id === prizeId)?.label || "Giải thưởng";

      if (prizeId) {
        setResults(oldResults => ({
          ...oldResults,
          [prizeId]: [...oldResults[prizeId], finalNumber]
        }));

        setLastSessionWinner({ prizeId, number: finalNumber });
        setCelebration({ prizeLabel, number: finalNumber });
      }

      return {
        ...prev,
        isDrawing: false,
        rollingNumber: finalNumber,
        secondsRemaining: 0,
        totalDuration: 0,
        finalWinner: null,
        currentProgress: 0
      };
    });
  }, [playWinSound]);

  const handleActualReset = () => {
    initAudio();
    const clearedResults: any = {};
    PRIZES.forEach(p => clearedResults[p.id] = []);
    setResults(clearedResults);
    setSelectedPrize(defaultPrizeId);
    setCelebration(null);
    setLastSessionWinner(null);
    setShowResetConfirm(false);
    setDrawState({
      isDrawing: false,
      rollingNumber: '00',
      targetPrize: null,
      secondsRemaining: 0,
      totalDuration: 0,
      finalWinner: null,
      currentProgress: 100
    });
  };

  const handleDrawAgain = () => {
    setCelebration(null);
    setTimeout(() => {
      startDraw(drawDuration);
    }, 300);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && showResetConfirm) {
        setShowResetConfirm(false);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [showResetConfirm]);

  useEffect(() => {
    return () => {
      if (rollingRef.current) clearInterval(rollingRef.current);
      if (timerRef.current) clearTimeout(timerRef.current);
      if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  const radius = 28;
  const circumference = 2 * Math.PI * radius;
  const dashOffset = circumference - (drawState.currentProgress / 100) * circumference;

  // HUD Circle settings
  const hudRadius = 50;
  const hudCircumference = 2 * Math.PI * hudRadius;
  const hudDashOffset = hudCircumference - (drawState.currentProgress / 100) * hudCircumference;

  const isDanger = drawState.secondsRemaining <= 2 && drawState.isDrawing;
  const isUrgent = drawState.secondsRemaining <= 5 && drawState.isDrawing;
  const activePrizeLabel = PRIZES.find(p => p.id === drawState.targetPrize)?.label;

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-slate-100 relative">

      {/* GLOBAL COUNTDOWN PROGRESS BAR */}
      <div className={`fixed top-0 left-0 w-full h-1.5 z-[200] transition-opacity duration-300 ${drawState.isDrawing ? 'opacity-100' : 'opacity-0'}`}>
        <div 
          className={`h-full transition-all duration-75 ease-linear shadow-[0_0_10px_rgba(37,99,235,0.5)] ${isDanger ? 'bg-red-500' : 'bg-blue-600'}`}
          style={{ width: `${drawState.currentProgress}%` }}
        ></div>
      </div>

      {/* Reset Confirmation Modal */}
      {showResetConfirm && (
        <div 
          className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300"
          onClick={() => setShowResetConfirm(false)}
        >
          <div 
            className="bg-white rounded-[2rem] p-8 max-w-sm w-full shadow-2xl animate-in zoom-in-95 duration-200"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mb-6">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <h3 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Xóa tất cả kết quả?</h3>
              <p className="text-slate-500 mb-8 leading-relaxed">
                Hành động này sẽ xóa sạch danh sách trúng thưởng và các số đã quay. Bạn không thể hoàn tác thao tác này.
              </p>
              <div className="flex flex-col gap-3 w-full">
                <button
                  onClick={handleActualReset}
                  className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 transition-all shadow-lg active:scale-95"
                >
                  XÁC NHẬN RESET
                </button>
                <button
                  onClick={() => setShowResetConfirm(false)}
                  className="w-full py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors"
                >
                  HỦY BỎ
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Celebration Overlay */}
      {celebration && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-500">
          <div className="bg-white rounded-[2rem] p-10 max-md w-full shadow-[0_0_50px_rgba(255,255,255,0.2)] text-center relative overflow-hidden animate-in zoom-in-90 slide-in-from-bottom-10 duration-500">
            {[...Array(20)].map((_, i) => (
              <div 
                key={i} 
                className="absolute w-3 h-3 rounded-sm opacity-60 pointer-events-none"
                style={{
                  backgroundColor: ['#ef4444', '#3b82f6', '#f59e0b', '#10b981', '#8b5cf6'][i % 5],
                  top: '-20px',
                  left: `${Math.random() * 100}%`,
                  animation: `fall ${1.5 + Math.random() * 2}s linear infinite`,
                  animationDelay: `${Math.random() * 2}s`,
                  transform: `rotate(${Math.random() * 360}deg)`
                }}
              />
            ))}
            <div className="mb-6 flex justify-center">
              <div className="w-20 h-20 bg-amber-100 rounded-full flex items-center justify-center animate-bounce">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-7.714 2.143L11 21l-2.286-6.857L1 12l7.714-2.143L11 3z" />
                </svg>
              </div>
            </div>
            <h2 className="text-4xl font-black bg-clip-text text-transparent bg-gradient-to-r from-red-600 to-orange-500 mb-2 uppercase tracking-tighter">
              THẮNG GIẢI!
            </h2>
            <p className="text-slate-500 font-bold mb-8 text-xl uppercase tracking-widest">{celebration.prizeLabel}</p>
            <div className="mb-10 relative inline-block group">
              <div className="absolute inset-0 bg-amber-400 blur-2xl opacity-30 group-hover:opacity-50 transition-opacity animate-pulse"></div>
              <span className="relative block text-9xl font-black font-mono text-slate-900 border-b-[12px] border-amber-400 leading-none pb-4 tracking-tighter">
                {celebration.number}
              </span>
            </div>
            <div className="flex flex-col sm:flex-row gap-3 w-full">
              <button
                onClick={() => setCelebration(null)}
                className="flex-1 py-4 bg-slate-200 text-slate-800 rounded-2xl font-black text-lg hover:bg-slate-300 transition-all shadow-md active:scale-95"
              >
                CHẤP NHẬN
              </button>
              <button
                onClick={handleDrawAgain}
                disabled={remainingCount === 0}
                className={`flex-1 py-4 bg-gradient-to-r from-blue-600 to-blue-700 text-white rounded-2xl font-black text-lg hover:from-blue-700 hover:to-blue-800 transition-all shadow-xl hover:shadow-2xl active:scale-95 border-b-4 border-blue-900 ${remainingCount === 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                QUAY LẠI
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="max-w-4xl w-full bg-white shadow-2xl rounded-2xl p-6 md:p-10 border border-gray-200 relative overflow-hidden">

        {drawState.isDrawing && (
          <div className={`absolute top-0 left-0 w-full p-3 text-center animate-in slide-in-from-top-full duration-500 flex items-center justify-center gap-4 border-b ${isDanger ? 'bg-red-50 border-red-200' : 'bg-blue-50 border-blue-200'}`}>
            <div className="flex items-center gap-2">
              <span className={`w-3 h-3 rounded-full ${isDanger ? 'bg-red-600 animate-ping' : 'bg-blue-600 animate-pulse'}`}></span>
              <span className={`text-sm font-black uppercase tracking-widest ${isDanger ? 'text-red-700' : 'text-blue-700'}`}>
                Đang quay {activePrizeLabel}
              </span>
            </div>
            <div className={`px-4 py-1 rounded-full font-black text-lg border-2 shadow-sm transition-all duration-300 ${isDanger ? 'bg-red-600 text-white border-red-700 animate-bounce' : 'bg-white text-blue-600 border-blue-600'}`}>
              {drawState.secondsRemaining}s
            </div>
          </div>
        )}

        <header className={`mb-8 text-center transition-all duration-500 ${drawState.isDrawing ? 'pt-10' : ''}`}>
          <h1 className="text-4xl font-extrabold text-red-600 uppercase tracking-tighter drop-shadow-sm">
            Chương Trình Quay Số
          </h1>
          <p className="text-gray-500 font-medium uppercase tracking-widest text-sm mt-1">May Mắn Mỗi Ngày</p>
        </header>

        {remainingCount < 5 && (
          <div className={`mb-6 p-4 rounded-xl flex items-center gap-4 border-2 shadow-lg animate-in slide-in-from-top-4 duration-500 ${
            remainingCount === 0 
              ? 'bg-red-50 border-red-500 text-red-700 animate-pulse' 
              : 'bg-amber-50 border-amber-400 text-amber-800'
          }`}>
            <div className={`p-2 rounded-full ${remainingCount === 0 ? 'bg-red-100 text-red-600' : 'bg-amber-100 text-amber-600'}`}>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <div className="flex-1">
              <h4 className="font-black text-lg uppercase tracking-tight">
                {remainingCount === 0 ? 'Đã hết số quay duy nhất!' : 'Sắp hết số quay!'}
              </h4>
              <div key={remainingCount} className={remainingCount < 5 ? 'animate-subtle-bounce' : ''}>
                <p className="text-sm font-medium opacity-80 leading-tight">
                  {remainingCount === 0 
                    ? 'Vui lòng nhấn RESET GIẢI bên dưới để bắt đầu một lượt chơi mới.' 
                    : `Chỉ còn lại ${remainingCount} số duy nhất chưa trúng thưởng. Hãy cân nhắc reset sớm.`}
                </p>
              </div>
            </div>
          </div>
        )}

        <div className="overflow-hidden rounded-xl border border-gray-300 shadow-sm mb-8">
          <table className="w-full border-collapse bg-white">
            <thead>
              <tr className="bg-slate-800 text-white">
                <th className="p-4 text-center w-20 border-r border-slate-700">CHỌN</th>
                <th className="p-4 text-left w-32 md:w-40 border-r border-slate-700">GIẢI</th>
                <th className="p-4 text-left">KẾT QUẢ</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {PRIZES.map((prize) => {
                const isSelected = selectedPrize === prize.id;
                const isTargeted = drawState.isDrawing && drawState.targetPrize === prize.id;
                const isWinner = lastSessionWinner?.prizeId === prize.id;
                const prizeResults = results[prize.id];

                return (
                  <tr 
                    key={prize.id} 
                    onClick={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                    className={`transition-all duration-300 cursor-pointer relative group ${
                      isSelected 
                        ? 'bg-blue-50/80 ring-1 ring-blue-100 ring-inset z-10' 
                        : 'hover:bg-gray-50'
                    }`}
                  >
                    <td className={`p-4 text-center border-r border-gray-200 transition-all duration-300 ${
                      isSelected ? 'border-l-[6px] border-l-blue-600 shadow-inner' : 'border-l-[6px] border-l-transparent'
                    }`}>
                      <div 
                        key={isSelected ? `active-${prize.id}` : `inactive-${prize.id}`}
                        className={`flex justify-center ${isSelected ? 'animate-radio-zoom-shake' : ''}`}
                      >
                        <input
                          type="radio"
                          name="prizeSelection"
                          id={`prize-${prize.id}`}
                          checked={isSelected}
                          onChange={() => !drawState.isDrawing && setSelectedPrize(prize.id)}
                          disabled={drawState.isDrawing}
                          className="w-6 h-6 cursor-pointer accent-blue-600 transition-transform"
                        />
                      </div>
                    </td>
                    <td className={`p-4 border-r border-gray-200 transition-all ${
                      isSelected || isWinner ? 'font-black' : 'text-gray-700'
                    }`}>
                      <label 
                        key={`${prize.id}-${isSelected}-${isWinner}`}
                        htmlFor={`prize-${prize.id}`} 
                        className={`cursor-pointer block w-full whitespace-nowrap font-bold transition-all duration-300 origin-left ${
                          isWinner 
                            ? 'animate-winner-label-glow text-xl' 
                            : isSelected 
                              ? 'animate-gentle-label-pulse text-lg' 
                              : 'scale-100'
                        }`}
                      >
                        {prize.label}
                      </label>
                    </td>
                    <td className="p-4 min-h-[70px]">
                      <div className={`flex flex-wrap items-center gap-2 transition-transform duration-300 origin-left ${
                        isSelected ? 'scale-[1.02]' : 'scale-100'
                      }`}>
                        {prizeResults.map((res, idx) => {
                          const isLastWinner = lastSessionWinner?.prizeId === prize.id && idx === prizeResults.length - 1;
                          return (
                            <React.Fragment key={`${prize.id}-${res}-${idx}`}>
                              <span className={`text-xl font-bold font-mono text-gray-900 bg-white border border-gray-200 px-3 py-1 rounded shadow-sm animate-pop-in ${
                                isLastWinner ? 'animate-highlight-vibrate ring-2 ring-red-500 ring-offset-1 border-red-500' : ''
                              }`}>
                                {res}
                              </span>
                              {idx < prizeResults.length - 1 && <span className="text-gray-400 font-bold">-</span>}
                            </React.Fragment>
                          );
                        })}

                        {isTargeted && (
                          <div className="flex items-center gap-4 ml-4">
                            {prizeResults.length > 0 && <span className="text-gray-400 font-bold">-</span>}
                            <div className="relative flex items-center justify-center p-1">
                              <svg className="w-20 h-20 transform -rotate-90">
                                <circle cx="40" cy="40" r={radius} stroke="currentColor" strokeWidth="6" fill="transparent" className="text-gray-100" />
                                <circle
                                  cx="40" cy="40" r={radius}
                                  stroke="currentColor" strokeWidth="6" fill="transparent"
                                  strokeDasharray={circumference}
                                  strokeDashoffset={dashOffset}
                                  strokeLinecap="round"
                                  className={`transition-all duration-100 ease-linear shadow-sm ${
                                    isDanger ? 'text-red-500' : drawState.totalDuration <= 3 ? 'text-orange-500' : 'text-blue-600'
                                  }`}
                                />
                              </svg>
                              <div className="absolute inset-0 flex flex-col items-center justify-center">
                                <span className={`text-[11px] font-black leading-none mb-0.5 transition-colors duration-300 ${isDanger ? 'text-red-600 animate-pulse' : 'text-gray-400'}`}>
                                  {drawState.secondsRemaining}s
                                </span>
                                <span className={`text-3xl font-black font-mono leading-none drop-shadow-sm transition-all duration-300 ${isDanger ? 'text-red-600 scale-125' : 'text-red-500 scale-110'} ${drawState.isDrawing ? 'animate-pulse' : ''}`}>
                                  {drawState.rollingNumber}
                                </span>
                              </div>
                            </div>
                          </div>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {/* MAIN HUD COUNTDOWN & ROLLING NUMBER (REFINED VISUAL TIMER) */}
        {drawState.isDrawing && (
          <div className="mb-8 flex flex-col items-center justify-center animate-in zoom-in-95 duration-500">
            <div className="relative flex items-center justify-center">
              {/* Animated Glow Rings */}
              <div className={`absolute inset-[-10px] rounded-full opacity-20 blur-xl animate-pulse ${isDanger ? 'bg-red-500' : 'bg-blue-500'}`}></div>
              <div className={`absolute inset-0 rounded-full opacity-10 animate-ping ${isDanger ? 'bg-red-600' : 'bg-blue-600'}`}></div>

              {/* Circular Progress Bar around the Rolling Number */}
              <svg className="w-48 h-48 transform -rotate-90 drop-shadow-lg">
                <circle cx="96" cy="96" r={hudRadius} stroke="currentColor" strokeWidth="10" fill="transparent" className="text-slate-100" />
                <circle
                  cx="96" cy="96" r={hudRadius}
                  stroke="currentColor" strokeWidth="10" fill="transparent"
                  strokeDasharray={hudCircumference}
                  strokeDashoffset={hudDashOffset}
                  strokeLinecap="round"
                  className={`transition-all duration-150 ease-linear ${
                    isDanger ? 'text-red-600' : drawState.totalDuration <= 3 ? 'text-orange-500' : 'text-blue-600'
                  }`}
                />
              </svg>

              {/* Rolling Number Display in the Center */}
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <div className={`text-7xl font-black font-mono tracking-tighter transition-all duration-75 drop-shadow-md ${isDanger ? 'text-red-600 scale-110' : 'text-slate-900'}`}>
                  {drawState.rollingNumber}
                </div>
                {/* Countdown Time Sub-label */}
                <div 
                  key={drawState.secondsRemaining} 
                  className={`mt-[-4px] px-3 py-0.5 rounded-full text-xs font-black uppercase tracking-[0.2em] shadow-sm transition-all duration-300 animate-in zoom-in-110
                    ${isUrgent ? 'animate-subtle-bounce bg-red-600 text-white' : 'bg-slate-800 text-white'}`
                  }
                >
                  {drawState.secondsRemaining} GIÂY
                </div>
              </div>
            </div>

            <div className="mt-4 text-center">
              <span className={`text-sm font-black uppercase tracking-widest transition-colors duration-300 ${isDanger ? 'text-red-600 animate-pulse' : 'text-slate-500'}`}>
                {isUrgent ? 'SẮP CÓ KẾT QUẢ...' : 'ĐANG QUAY SỐ...'}
              </span>
            </div>
          </div>
        )}

        <div className="mb-6 bg-slate-50 p-6 rounded-2xl border border-slate-200">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-blue-100 rounded-xl text-blue-600">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
              <div>
                <h4 className="text-slate-900 font-black text-sm uppercase tracking-tight">Thời gian quay số</h4>
                <p className="text-slate-500 text-xs font-medium">Kéo để điều chỉnh tốc độ</p>
              </div>
            </div>

            <div className="flex-1 max-w-md flex items-center gap-6">
              <input
                type="range"
                min="3"
                max="15"
                step="1"
                value={drawDuration}
                onChange={(e) => setDrawDuration(parseInt(e.target.value))}
                disabled={drawState.isDrawing}
                className="flex-1 h-2.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-600 disabled:opacity-50 disabled:cursor-not-allowed"
              />
              <div className="min-w-[70px] bg-white border-2 border-blue-600 rounded-xl px-3 py-1.5 text-center shadow-sm">
                <span className="text-blue-700 font-black text-xl">{drawDuration}</span>
                <span className="text-blue-600 font-bold text-xs ml-0.5">S</span>
              </div>
            </div>
          </div>
        </div>

        <div className="flex flex-col gap-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <button
              onClick={() => startDraw(drawDuration)}
              disabled={drawState.isDrawing || remainingCount === 0}
              className={`
                relative py-5 px-6 rounded-2xl font-black text-xl uppercase tracking-widest shadow-xl transform active:scale-95 transition-all
                ${drawState.isDrawing || remainingCount === 0
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed border-none' 
                  : 'bg-gradient-to-r from-blue-600 to-blue-700 text-white hover:from-blue-700 hover:to-blue-800 border-b-4 border-blue-900'}
              `}
            >
              {drawState.isDrawing && drawState.totalDuration === drawDuration ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Đang quay...
                </span>
              ) : `Bắt đầu quay (${drawDuration}s)`}
            </button>

            <button
              onClick={() => startDraw(3)}
              disabled={drawState.isDrawing || remainingCount === 0}
              className={`
                relative py-5 px-6 rounded-2xl font-black text-xl uppercase tracking-widest shadow-xl transform active:scale-95 transition-all
                ${drawState.isDrawing || remainingCount === 0
                  ? 'bg-gray-300 text-gray-500 cursor-not-allowed border-none' 
                  : 'bg-gradient-to-r from-amber-500 to-orange-600 text-white hover:from-amber-600 hover:to-orange-700 border-b-4 border-orange-800'}
              `}
            >
              {drawState.isDrawing && drawState.totalDuration === 3 ? (
                <span className="flex items-center justify-center gap-2">
                  <svg className="animate-spin h-6 w-6 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Quay nhanh...
                </span>
              ) : 'Quay Nhanh (3s)'}
            </button>
          </div>

          <button
            onClick={() => setShowResetConfirm(true)}
            disabled={drawState.isDrawing}
            className={`
              w-full py-4 rounded-2xl font-black text-xl uppercase tracking-widest shadow-lg transform active:scale-95 transition-all
              ${drawState.isDrawing 
                ? 'opacity-40 cursor-not-allowed' 
                : 'bg-white text-red-600 border-2 border-red-600 hover:bg-red-50'}
            `}
          >
            RESET GIẢI
          </button>
        </div>

        <div className="mt-8 flex flex-col gap-3">
          <div className="flex flex-wrap justify-between items-center text-xs font-bold uppercase text-gray-500 tracking-wider">
            <div className="flex gap-4">
              <span className="flex items-center gap-1.5">
                <span className="w-2 h-2 rounded-full bg-green-500"></span>
                CÒN LẠI: <span key={remainingCount} className={`text-slate-900 inline-block transition-all ${drawState.isDrawing ? '' : 'animate-subtle-bounce'}`}>{remainingCount}/100</span>
              </span>
              <span className="flex items-center gap-1.5">
                <span className="w-2 h-2 rounded-full bg-blue-500"></span>
                ĐÃ DÙNG: <span key={usedNumbers.size} className={`text-slate-900 inline-block transition-all ${drawState.isDrawing ? '' : 'animate-subtle-bounce'}`}>{usedNumbers.size}/100</span>
              </span>
            </div>
            <div className="mt-1 sm:mt-0 text-[10px] text-gray-400 font-medium">CHẾ ĐỘ: KHÔNG TRÙNG LẶP</div>
          </div>
        </div>
      </div>

      <p className="mt-6 text-gray-400 text-xs text-center max-w-md px-4">
        Hệ thống tự động loại bỏ các số đã trúng thưởng. Kết quả hiển thị tại cột 3 và được lưu trữ liên tục. 
        Nhấn RESET để xóa sạch kết quả.
      </p>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { PrizeId, DrawingState } from './types';
import { PRIZES, DRAW_DURATION_SECONDS, ROLL_INTERVAL_MS } from './constants';

const App: React.FC = () => {
  const defaultPrizeId = PRIZES[PRIZES.length - 1].id;
  const [selectedPrize, setSelectedPrize] = useState<PrizeId>(defaultPrizeId);
  const [drawDuration, setDrawDuration] = useState<number>(DRAW_DURATION_SECONDS);

  const [results, setResults] = useState<Record<PrizeId, string[]>>(() => {
    const initial: any = {};
    PRIZES.forEach(p => initial[p.id] = []);
    return initial;
  });

  const [drawState, setDrawState] = useState<DrawingState & { finalWinner: string | null; currentProgress: number }>({
    isDrawing: false,
    rollingNumber: '00',
    targetPrize: null,
    secondsRemaining: 0,
    totalDuration: 0,
    finalWinner: null,
    currentProgress: 100
  });

  const [celebration, setCelebration] = useState<{ prizeLabel: string, number: string } | null>(null);
  const [showResetConfirm, setShowResetConfirm] = useState(false);
  const [lastSessionWinner, setLastSessionWinner] = useState<{ prizeId: PrizeId, number: string } | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  const initAudio = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    if (audioContextRef.current.state === 'suspended') {
      audioContextRef.current.resume();
    }
  };

  const playClickSound = useCallback(() => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.type = 'sine';
    osc.frequency.setValueAtTime(150, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(40, ctx.currentTime + 0.1);

    gain.gain.setValueAtTime(0.05, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.005, ctx.currentTime + 0.1);

    osc.connect(gain);
    gain.connect(ctx.destination);

    osc.start();
    osc.stop(ctx.currentTime + 0.1);
  }, []);

  const playWinSound = useCallback(() => {
    if (!audioContextRef.current) return;
    const ctx = audioContextRef.current;

    const playNote = (freq: number, startTime: number, duration: number) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'triangle';
      osc.frequency.setValueAtTime(freq, startTime);
      gain.gain.setValueAtTime(0, startTime);
      gain.gain.linearRampToValueAtTime(0.2, startTime + 0.05);
      gain.gain.exponentialRampToValueAtTime(0.01, startTime + duration);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start(startTime);
      osc.stop(startTime + duration);
    };

    const now = ctx.currentTime;
    playNote(523.25, now, 0.4); 
    playNote(659.25, now + 0.1, 0.4); 
    playNote(783.99, now + 0.2, 0.6); 
    playNote(1046.50, now + 0.35, 0.8);
  }, []);

  const usedNumbers = useMemo(() => {
    return new Set(Object.values(results).flat());
  }, [results]);

  const remainingCount = 100 - usedNumbers.size;

  const timerRef = useRef<any>(null);
  const rollingRef = useRef<any>(null);

  const startDraw = useCallback((duration: number) => {
    if (drawState.isDrawing) return;
    initAudio();
    setCelebration(null);
    setLastSessionWinner(null);

    const availableNumbers: string[] = [];
    for (let i = 0; i < 100; i++) {
      const num = i.toString().padStart(2, '0');
      if (!usedNumbers.has(num)) {
        availableNumbers.push(num);
      }
    }

    if (availableNumbers.length === 0) {
      alert("Đã hết số để quay! Vui lòng Reset giải để bắt đầu lại.");
      return;
    }

    const randomIndex = Math.floor(Math.random() * availableNumbers.length);
    const chosenWinner = availableNumbers[randomIndex];

    setDrawState(prev => ({
      ...prev,
      isDrawing: true,
      rollingNumber: '00',
      targetPrize: selectedPrize,
      secondsRemaining: duration,
      totalDuration: duration,
      finalWinner: chosenWinner,
      currentProgress: 100
    }));

    rollingRef.current = setInterval(() => {
      const randomNum = Math.floor(Math.random() * 100);
      const padded = randomNum.toString().padStart(2, '0');
      setDrawState(prev => ({ ...prev, rollingNumber: padded }));
      playClickSound();
    }, ROLL_INTERVAL_MS);

    const startTime = Date.now();
    const endTime = startTime + duration * 1000;

    const tick = () => {
      const now = Date.now();
      const remainingMs = Math.max(0, endTime - now);
      const remainingSecs = Math.ceil(remainingMs / 1000);
      const progress = (remainingMs / (duration * 1000)) * 100;

      setDrawState(prev => ({ 
        ...prev, 
        secondsRemaining: remainingSecs,
        currentProgress: progress
      }));

      if (now >= endTime) {
        finishDraw();
      } else {
        timerRef.current = setTimeout(tick, 30);
      }
    };

    timerRef.current = setTimeout(tick, 30);
  }, [selectedPrize, drawState.isDrawing, usedNumbers, playClickSound]);

  const finishDraw = useCallback(() => {
    if (rollingRef.current) clearInterval(rollingRef.current);
    if (timerRef.current) clearTimeout(timerRef.current);
    playWinSound();

    setDrawState(prev => {
      const finalNumber = prev.finalWinner || prev.rollingNumber;
      const prizeId = prev.targetPrize;
      const prizeLabel = PRIZES.find(p => p.id === prizeId)?.label || "Giải thưởng";

      if (prizeId) {
        setResults(oldResults => ({
          ...oldResults,
          [prizeId]: [...oldResults[prizeId], finalNumber]
        }));

        setLastSessionWinner({ prizeId, number: finalNumber });
        setCelebration({ prizeLabel, number: finalNumber });
      }

      return {
        ...prev,
        isDrawing: false,
        rollingNumber: finalNumber,
        secondsRemaining: 0,
        totalDuration: 0,
        finalWinner: null,
        currentProgress: 0
      };
    });
  }, [playWinSound]);

  const handleActualReset = () => {
    initAudio();
    const clearedResults: any = {};
    PRIZES.forEach(p => clearedResults[p.id] = []);
    setResults(clearedResults);
    setSelectedPrize(defaultPrizeId);
    setCelebration(null);
    setLastSessionWinner(null);
    setShowResetConfirm(false);
    setDrawState({
      isDrawing: false,
      rollingNumber: '00',
      targetPrize: null,
      secondsRemaining: 0,
      totalDuration: 0,
      finalWinner: null,
      currentProgress: 100
    });
  };

  const handleDrawAgain = () => {
    setCelebration(null);
    setTimeout(() => {
      startDraw(drawDuration);
    }, 300);
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && showResetConfirm) {
        setShowResetConfirm(false);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [showResetConfirm]);

  useEffect(() => {
    return () => {
      if (rollingRef.current) clearInterval(rollingRef.current);
      if (timerRef.current) clearTimeout(timerRef.current);
      if (audioContextRef.current) audioContextRef.current.close();
    };
  }, []);

  const radius = 28;
  const circumference = 2 * Math.PI * radius;
  const dashOffset = circumference - (drawState.currentProgress / 100) * circumference;

  // HUD Circle settings
  const hudRadius = 50;
  const hudCircumference = 2 * Math.PI * hudRadius;
  const hudDashOffset = hudCircumference - (drawState.currentProgress / 100) * hudCircumference;

  const isDanger = drawState.secondsRemaining <= 2 && drawState.isDrawing;
  const isUrgent = drawState.secondsRemaining <= 5 && drawState.isDrawing;
  const activePrizeLabel = PRIZES.find(p => p.id === drawState.targetPrize)?.label;

  return (
    <div className="min-h-screen flex flex-col items-center justify-center p-4 bg-slate-100 relative">

      {/* GLOBAL COUNTDOWN PROGRESS BAR */}
      <div className={`fixed top-0 left-0 w-full h-1.5 z-[200] transition-opacity duration-300 ${drawState.isDrawing ? 'opacity-100' : 'opacity-0'}`}>
        <div 
          className={`h-full transition-all duration-75 ease-linear shadow-[0_0_10px_rgba(37,99,235,0.5)] ${isDanger ? 'bg-red-500' : 'bg-blue-600'}`}
          style={{ width: `${drawState.currentProgress}%` }}
        ></div>
      </div>

      {/* Reset Confirmation Modal */}
      {showResetConfirm && (
        <div 
          className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300"
          onClick={() => setShowResetConfirm(false)}
        >
          <div 
            className="bg-white rounded-[2rem] p-8 max-w-sm w-full shadow-2xl animate-in zoom-in-95 duration-200"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mb-6">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-red-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <h3 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Xóa tất cả kết quả?</h3>
              <p className="text-slate-500 mb-8 leading-relaxed">
                Hành động này sẽ xóa sạch danh sách trúng thưởng và các số đã quay. Bạn không thể hoàn tác thao tác này.
              </p>
              <div className="flex flex-col gap-3 w-full">
                <button
                  onClick={handleActualReset}
                  className="w-full py-4 bg-red-600 text-white font-black rounded-2xl hover:bg-red-700 transition-all shadow-lg active:scale-95"
                >
                  XÁC NHẬN RESET
                </button>
                <button
                  onClick={() => setShowResetConfirm(false)}
                  className="w-full py-4 bg-slate-100 text-slate-600 font-bold rounded-2xl hover:bg-slate-200 transition-colors"
                >
                  HỦY BỎ
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Celebration Overlay */}
      {celebration && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-500">
          <div className="bg-white rounded-[2rem] p-10 max-md w-full shadow-[0_0_50px_rgba(255,255,255,0.2)] text-center relative overflow-hidden animate-in zoom-in-90 slide-in-from-bottom-10 duration-500">
            {[...Array(20)].map((_, i) => (
              <div 
                key={i} 
                className="absolute w-3 h-3 rounded-sm opacity-60 pointer-events-none"
                style={{
